import{_ as a,o,c as t,S as n}from"./chunks/framework.C6RQlTYc.js";const u=JSON.parse('{"title":"Token 与分词","description":"","frontmatter":{},"headers":[],"relativePath":"直击概念/17ai/s_ai_8-tokenization.md","filePath":"直击概念/17ai/s_ai_8-tokenization.md","lastUpdated":1778207238000}'),i={name:"直击概念/17ai/s_ai_8-tokenization.md"};function r(l,e,h,d,s,c){return o(),t("div",null,[...e[0]||(e[0]=[n('<h1 id="token-与分词" tabindex="-1">Token 与分词 <a class="header-anchor" href="#token-与分词" aria-label="Permalink to &quot;Token 与分词&quot;">​</a></h1><h2 id="概念" tabindex="-1">概念 <a class="header-anchor" href="#概念" aria-label="Permalink to &quot;概念&quot;">​</a></h2><p>Token（词元）是大语言模型处理文本的<strong>最小单位</strong>。分词（Tokenization）是将原始文本转换为 token 序列的过程。LLM 不直接理解字符或单词，而是理解 token。</p><p>一个 token 大约相当于：</p><ul><li>英文：0.75 个单词</li><li>中文：0.5 ~ 1 个汉字</li><li>代码：取决于语言结构</li></ul><p><strong>示例</strong>：<code>&quot;Hello, world!&quot;</code> → <code>[&quot;Hello&quot;, &quot;,&quot;, &quot; world&quot;, &quot;!&quot;]</code>（4 个 token）</p><h2 id="常见分词算法" tabindex="-1">常见分词算法 <a class="header-anchor" href="#常见分词算法" aria-label="Permalink to &quot;常见分词算法&quot;">​</a></h2><h3 id="bpe-byte-pair-encoding" tabindex="-1">BPE（Byte Pair Encoding） <a class="header-anchor" href="#bpe-byte-pair-encoding" aria-label="Permalink to &quot;BPE（Byte Pair Encoding）&quot;">​</a></h3><p>GPT 系列使用的算法。从字符开始，反复合并最高频的相邻 token 对，直到达到预设词汇表大小。</p><ul><li><strong>优点</strong>：能处理未见过的新词（通过合并已知子词）</li><li><strong>缺点</strong>：词汇表需要精心控制大小</li></ul><h3 id="wordpiece" tabindex="-1">WordPiece <a class="header-anchor" href="#wordpiece" aria-label="Permalink to &quot;WordPiece&quot;">​</a></h3><p>BERT 使用的算法。与 BPE 类似，但合并时选择能最大化训练数据似然度的 token 对。</p><h3 id="sentencepiece" tabindex="-1">SentencePiece <a class="header-anchor" href="#sentencepiece" aria-label="Permalink to &quot;SentencePiece&quot;">​</a></h3><p>LLaMA、Mistral 等使用的算法。直接将原始文本当作字节流处理，不依赖预分词。</p><h3 id="unigram" tabindex="-1">Unigram <a class="header-anchor" href="#unigram" aria-label="Permalink to &quot;Unigram&quot;">​</a></h3><p>T5 等使用的算法。从一个大的词汇表开始，通过删除低概率的 token 来缩减。</p><h2 id="token-的实际影响" tabindex="-1">Token 的实际影响 <a class="header-anchor" href="#token-的实际影响" aria-label="Permalink to &quot;Token 的实际影响&quot;">​</a></h2><h3 id="token-限制-上下文窗口" tabindex="-1">Token 限制（上下文窗口） <a class="header-anchor" href="#token-限制-上下文窗口" aria-label="Permalink to &quot;Token 限制（上下文窗口）&quot;">​</a></h3><p>每个 LLM 有最大 token 数限制（如 GPT-4 的 128K），输入+输出合在一起不能超过此限制。超过就需要截断或压缩。</p><h3 id="token-计费" tabindex="-1">Token 计费 <a class="header-anchor" href="#token-计费" aria-label="Permalink to &quot;Token 计费&quot;">​</a></h3><p>API 服务按 token 计费：</p><ul><li><strong>输入 token</strong>（prompt）：通常价格较低</li><li><strong>输出 token</strong>（completion）：通常价格较高</li><li>不同模型价格差异巨大（DeepSeek V3 输入约 ¥1/百万 token，GPT-4o 输入约 $2.5/百万 token）</li></ul><h3 id="前端实践" tabindex="-1">前端实践 <a class="header-anchor" href="#前端实践" aria-label="Permalink to &quot;前端实践&quot;">​</a></h3><ul><li>预估 token 消耗来优化成本（使用 <code>tiktoken</code> 等库）</li><li>控制上下文大小，避免超出模型限制</li><li>中英文混用和特殊字符会增加 token 消耗</li></ul><h2 id="面试常问" tabindex="-1">面试常问 <a class="header-anchor" href="#面试常问" aria-label="Permalink to &quot;面试常问&quot;">​</a></h2><ul><li>一个中文汉字大约等于多少 token？为什么不是 1:1？</li><li>如何在前端估算一段文本的 token 数量？</li><li>Token 数超过模型限制时，前端应该如何处理？</li></ul><h2 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-label="Permalink to &quot;参考&quot;">​</a></h2><ul><li><a href="https://platform.openai.com/tokenizer" target="_blank" rel="noreferrer">OpenAI Tokenizer</a></li><li><a href="https://huggingface.co/docs/tokenizers/index" target="_blank" rel="noreferrer">Hugging Face Tokenizers</a></li></ul>',28)])])}const p=a(i,[["render",r]]);export{u as __pageData,p as default};
